import { Network, Alchemy } from 'alchemy-sdk';

// API key access — set ALCHEMY_API_KEY env var
const alchemy = new Alchemy({
  apiKey: process.env.ALCHEMY_API_KEY,
  network: Network.ETH_MAINNET,
});

// Node API — latest block and token balances
const block = await alchemy.core.getBlockNumber();
const balances = await alchemy.core.getTokenBalances('0xYourAddress');
console.log(`Block: ${block}`, balances.tokenBalances);

// Webhooks — stream mined transactions to your agent
const hook = await alchemy.notify.createWebhook(
  'https://your-agent.com/webhook',
  WebhookType.MINED_TRANSACTION,
  { addresses: ['0xYourAddress'] },
);

// x402 micropayment access (pay-per-request, no API key needed)
import { wrapFetchWithPayment } from '@x402/fetch';
import { createWalletClient, http } from 'viem';

const client = createWalletClient({ transport: http() });
const fetchWithPayment = wrapFetchWithPayment(fetch, client);

const res = await fetchWithPayment('https://eth-mainnet.g.alchemy.com/v2/x402', {
  method: 'POST',
  body: JSON.stringify({ jsonrpc: '2.0', method: 'eth_blockNumber', params: [], id: 1 }),
});
const { result } = await res.json();
console.log('Latest block (x402):', parseInt(result, 16));
